pragma cashscript ^0.12.0;

contract AuthGuard(bytes tokenId) {
  function unlockWithNft(bool keepGuarded) {
    require(tx.inputs[1].tokenCategory == tokenId, "AUTHKEY_WRONG_CATEGORY");
    require(tx.inputs[1].tokenAmount == 0, "AUTHKEY_NOT_NFT_ONLY");

    if (keepGuarded) {
      require(
        tx.outputs[0].lockingBytecode
          == tx.inputs[this.activeInputIndex].lockingBytecode,
        "AUTHHEAD_NOT_PRESERVED"
      );
    }
  }
}
